// ── Navigation ────────────────────────────────────────────────────
let activeTab = 'projects';

function switchTab(tab){
  if(activeTab===tab) return;
  const goRight = tab==='library';
  document.getElementById('s-'+activeTab).classList.replace('on', goRight?'off-left':'off-right');
  document.getElementById('s-'+tab).classList.replace(goRight?'off-right':'off-left','on');
  document.getElementById('tab-'+activeTab).classList.remove('active');
  document.getElementById('tab-'+tab).classList.add('active');
  activeTab=tab;
  if(tab==='library') renderLibrary(); else renderProjects();
}
function goToLibrary(){ switchTab('library'); }
function goBackToProjects(){ switchTab('projects'); }

function goToDetail(type, id, from){
  currentDetailType=type; currentDetailId=id; detailFrom=from||activeTab;
  document.getElementById('back-lbl').textContent = detailFrom==='library'?'Library':'Projects';
  const eb=document.getElementById('d-edit-btn');
  if(eb) eb.style.display='block';
  if(type==='project'){
    const p=projects.find(x=>x.id===id);
    renderProjectDetail(p);
  } else {
    const p=patterns.find(x=>x.id===id);
    renderPatternDetail(p);
  }
  document.getElementById('s-detail').scrollTop=0;
  document.getElementById('s-'+detailFrom).classList.replace('on','off-left');
  document.getElementById('s-detail').classList.replace('off-right','on');
  document.getElementById('main-tab-bar').style.display='none';
}
function goBack(){
  document.getElementById('s-detail').classList.replace('on','off-right');
  document.getElementById('s-'+detailFrom).classList.replace('off-left','on');
  const eb=document.getElementById('d-edit-btn');
  if(eb) eb.style.display='none';
  currentDetailId=null; currentDetailType=null;
  document.getElementById('main-tab-bar').style.display='';
  document.getElementById('tab-projects').classList.toggle('active', detailFrom==='projects');
  document.getElementById('tab-library').classList.toggle('active', detailFrom==='library');
  activeTab=detailFrom;
  if(detailFrom==='projects') renderProjects();
  else if(detailFrom==='library') renderLibrary();
}
function toggleFavDetail(){
  if(currentDetailType==='project'){
    const p=projects.find(x=>x.id===currentDetailId);if(!p)return;
    p.fav=!p.fav; saveProjects();
    const hb=document.getElementById('hero-fav-btn');
    if(hb)hb.textContent=p.fav?'★':'☆';
  } else {
    const p=patterns.find(x=>x.id===currentDetailId);if(!p)return;
    p.fav=!p.fav; savePatterns();
    const hb=document.getElementById('hero-fav-btn');
    if(hb)hb.textContent=p.fav?'★':'☆';
  }
}
function triggerDetailEdit(){
  if(currentDetailType==='project') openEditProject(currentDetailId);
  else openEditPattern(currentDetailId);
}

// ── Projects list ─────────────────────────────────────────────────
function toggleProjSearch(){
  const wrap=document.getElementById('proj-search-wrap');
  const input=document.getElementById('proj-search');
  const isOpen=wrap.classList.contains('open');
  if(isOpen){
    wrap.classList.remove('open');
    input.value='';
    renderProjects();
  } else {
    wrap.classList.add('open');
    setTimeout(()=>input.focus(),50);
  }
}
function renderProjects(){
  const q=(document.getElementById('proj-search')?.value||'').toLowerCase();
  const st=document.getElementById('proj-status-filter').value;
  const list=projects.filter(p=>
    (!q||p.name.toLowerCase().includes(q)||(p.notes||'').toLowerCase().includes(q))&&
    (!st||p.status===st));
  document.getElementById('proj-count-lbl').textContent=
    `${projects.length} project${projects.length!==1?'s':''}`;
  const grid=document.getElementById('proj-grid');
  if(!list.length){grid.innerHTML='<div class="empty">No projects yet — tap + New to start one!</div>';return;}
  grid.innerHTML=list.map(p=>{
    const pat=patterns.find(x=>x.id===p.patternId);
    const steps=pat?(pat.notes||'').split('\n').filter(l=>l.trim()):
      (p.steps||[]);
    const done=getProjStepsDone(p.id);
    const pct=steps.length?Math.round(done.filter(i=>i<steps.length).length/steps.length*100):0;
    const statusCls=p.status==='Active'?'status-active':p.status==='Done'?'status-done-proj':'status-frogged';
    const cardCls=p.status==='Active'?'card-active':p.status==='Done'?'card-done':'card-frogged';
    const photo=p.photoKey?localStorage.getItem(p.photoKey):null;
    return `<div class="card ${cardCls}" onclick="goToDetail('project',${p.id},'projects')">
      ${photo?`<img class="card-photo" src="${photo}" alt=""/>`
              :`<div class="card-photo-placeholder"><svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg" width="44" height="44" opacity="0.45"><rect x="6" y="10" width="36" height="28" rx="4" stroke="#9b8ec4" stroke-width="2"/><circle cx="17" cy="20" r="3" stroke="#9b8ec4" stroke-width="2"/><path d="M6 32l9-8 7 7 5-4 9 9" stroke="#9b8ec4" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div>`}
      <button class="fav-btn${p.fav?' active':''}" onclick="event.stopPropagation();toggleFavProj(${p.id})" aria-label="Favourite">${p.fav?'★':'☆'}</button>
      <div class="proj-card-body">
        <div class="proj-card-row">
          <div class="proj-card-name">${esc(p.name)}</div>
          <span class="status-pill ${statusCls}">${p.status}</span>
        </div>
        <div class="proj-card-subtitle">${pat?esc(pat.name):'✦ Freestyle'}</div>
        ${steps.length?`<div class="proj-card-progress-wrap">
          <div class="proj-card-progress-bg">
            <div class="proj-card-progress-bar" style="width:${pct}%"></div>
          </div>
          <img class="proj-card-mascot" src="mascot.png" alt="" style="left:${Math.min(Math.max(pct,4),96)}%"/>
        </div>`:''}
      </div>
    </div>`;
  }).join('');
}
function toggleFavProj(id){
  const p=projects.find(x=>x.id===id);if(p){p.fav=!p.fav;saveProjects();renderProjects();}
}

// ── Project detail ────────────────────────────────────────────────
function isStepSectionHeader(line){
  if(/^R\d/.test(line)||/^Row\s*\d/i.test(line)||/^Rnd\s*\d/i.test(line)||/^\d+[.)]\s/.test(line)) return false;
  return (line.trim().endsWith(':') || line.includes(' \u2014 ') || line.includes(' \u2013 ')) && line.length < 80;
}
function toggleStepSection(secId){
  const sec=document.getElementById(secId);if(!sec)return;
  const body=sec.querySelector('.steps-section-body');
  const chev=sec.querySelector('.steps-section-chevron');
  const open=body.classList.contains('open');
  body.classList.toggle('open',!open);
  if(chev)chev.classList.toggle('open',!open);
}
function renderProjectDetail(p){
  const pat=patterns.find(x=>x.id===p.patternId);
  const lines=pat?(pat.notes||'').split('\n').filter(l=>l.trim()):(p.steps||[]);
  const hasSteps=lines.length>0;
  const done=getProjStepsDone(p.id);
  const total=lines.length;
  const doneCount=done.filter(i=>i<total).length;
  const pct=total?Math.round(doneCount/total*100):0;
  const photo=p.photoKey?localStorage.getItem(p.photoKey):null;
  const isDone=p.status==='Done';
  const statusCls=p.status==='Active'?'status-active':p.status==='Done'?'status-done-proj':'status-frogged';

  // Parse lines into section groups
  const sectionGroups=[];
  let curGroup=null;
  lines.forEach((line,i)=>{
    if(isStepSectionHeader(line)){
      curGroup={title:line.replace(/:$/,'').replace(/ [\u2014\u2013] .*/,'').trim(),items:[]};
      sectionGroups.push(curGroup);
    } else {
      if(!curGroup){curGroup={title:null,items:[]};sectionGroups.push(curGroup);}
      curGroup.items.push({line,idx:i});
    }
  });
  if(!sectionGroups.length && lines.length) sectionGroups.push({title:null,items:lines.map((line,i)=>({line,idx:i}))});

  const hasSections=sectionGroups.some(g=>g.title!==null);

  const sectionsHTML=sectionGroups.map((grp,gi)=>{
    const grpDone=grp.items.filter(item=>done.includes(item.idx)).length;
    const grpTotal=grp.items.length;
    const dotCls=grpDone===0?'':grpDone===grpTotal?'full':'partial';
    const stepsInner=grp.items.map(item=>`
      <div class="step-row${done.includes(item.idx)?' done':''}" id="pstep-${p.id}-${item.idx}" onclick="toggleProjStep(${p.id},${item.idx})">
        <div class="step-check"><span class="step-tick">\u2713</span></div>
        <div class="step-text">${esc(item.line)}</div>
      </div>`).join('');
    if(!hasSections||!grp.title){
      return `<div class="steps-section" id="sec-${p.id}-${gi}">
        <div class="steps-section-body open">${stepsInner}</div>
      </div>`;
    }
    return `<div class="steps-section" id="sec-${p.id}-${gi}">
      <div class="steps-section-hd" onclick="toggleStepSection('sec-${p.id}-${gi}')">
        <div class="steps-section-dot ${dotCls}"></div>
        <div class="steps-section-title">${esc(grp.title)}</div>
        <svg class="steps-section-chevron${gi===0?' open':''}" viewBox="0 0 12 8" fill="none" width="12" height="8"><path d="M1 1.5l5 5 5-5" stroke="#9b8ec4" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/></svg>
      </div>
      <div class="steps-section-body${gi===0?' open':''}">${stepsInner}</div>
    </div>`;
  }).join('');

  const stepsHTML=hasSteps?`
    <div class="section">
      <div class="section-lbl">
        <span>Steps</span>
        <button class="btn-reset" onclick="resetProjSteps(${p.id})">Reset all</button>
      </div>
      <div class="progress-meta">
        <span id="steps-lbl-${p.id}">${doneCount} of ${total}</span>
        <span id="steps-pct-${p.id}">${pct}%</span>
      </div>
      <div class="detail-progress-wrap">
        <div class="detail-progress-bg">
          <div class="detail-progress-bar" id="steps-bar-${p.id}" style="width:${pct}%"></div>
        </div>
        <img class="detail-progress-mascot" src="mascot.png" id="steps-mascot-${p.id}" style="left:${Math.min(Math.max(pct,4),96)}%" alt=""/>
      </div>
      <div class="steps-list">${sectionsHTML}</div>
      ${total>0?`<div id="finish-btn-wrap-${p.id}" style="display:${doneCount===total?'block':'none'};margin-top:14px;text-align:center">
        <button onclick="finishProject(${p.id})"
          style="background:linear-gradient(135deg,#6A4FC4,#4A9FD8);color:#fff;border:none;
          padding:13px 32px;border-radius:99px;font-size:15px;font-weight:800;
          font-family:inherit;cursor:pointer;box-shadow:0 4px 16px rgba(106,79,196,.35)">
          \uD83C\uDF89 Finish project</button>
      </div>`:''}
    </div>`:'';

  const photoSection=isDone?`
    <div class="section">
      <div class="section-lbl">Finished piece</div>
      ${photo
        ?`<img class="photo-preview" src="${photo}" alt="Finished piece"/>
          <button class="btn-remove-photo" onclick="removeProjectPhoto(${p.id})">Remove photo</button>`
        :`<div class="photo-upload-zone" onclick="document.getElementById('photo-fi-${p.id}').click()">
            <span style="font-size:32px">\uD83D\uDCF7</span>
            <p>Tap to add a photo of your finished piece</p>
          </div>
          <input type="file" id="photo-fi-${p.id}" accept="image/*" style="display:none"
            onchange="handlePhotoSelect(event,${p.id})"/>`}
    </div>`:'';

  document.getElementById('d-content').innerHTML=`
    <div style="max-width:640px;margin:0 auto">
      <div class="detail-hero">
        <div class="detail-hero-left">
          <div class="detail-hero-title">${esc(p.name)}</div>
          <div class="detail-hero-badges">
            ${pat?`<span class="hero-info-pill hero-info-pill--link" onclick="goToDetail('pattern',${pat.id},'projects')"><img src="book.png" class="hero-pill-img"> ${esc(pat.name)} ›</span>`:''}
            ${p.yarn?`<span class="hero-info-pill"><img src="yarn-ball.png" class="hero-pill-img"> ${esc(p.yarn)}</span>`:''}
            ${p.hook?`<span class="hero-info-pill hero-info-pill--hook"><img src="crochet.png" class="hero-pill-img"> ${esc(p.hook)}</span>`:''}
          </div>
        </div>
        <div class="detail-hero-photo-wrap">
          ${photo
            ?`<img class="detail-hero-img" src="${photo}" alt=""/>`
            :`<div class="detail-hero-photo-placeholder"><svg viewBox="0 0 48 48" fill="none" width="40" height="40" opacity="0.35"><rect x="6" y="10" width="36" height="28" rx="4" stroke="#9b8ec4" stroke-width="2"/><circle cx="17" cy="20" r="3" stroke="#9b8ec4" stroke-width="2"/><path d="M6 32l9-8 7 7 5-4 9 9" stroke="#9b8ec4" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div>`}
        </div>
        <button class="detail-hero-fav${p.fav?' active':''}" onclick="toggleFavDetail()" id="hero-fav-btn">${p.fav?'\u2605':'\u2606'}</button>
      </div>
      <div class="detail-body">
        ${p.notes?`<div class="section">
          <div class="section-lbl">Notes</div>
          <div style="background:rgba(255,255,255,.7);border-radius:0 var(--rl) var(--rl) 0;padding:10px 14px 12px;
            font-size:14px;line-height:1.7;white-space:pre-wrap;border-left:3px solid var(--ac);margin:0">${esc(p.notes)}</div>
        </div>`:''}
        ${stepsHTML}
        ${photoSection}
      </div>
    </div>`;
}

function toggleInfoStrip(header){
  const chevron=header.querySelector('.info-strip-chevron');
  const body=header.nextElementSibling;
  const isOpen=body.classList.contains('open');
  chevron.classList.toggle('open',!isOpen);
  body.classList.toggle('open',!isOpen);
}

// ── Photo handling ────────────────────────────────────────────────
function handlePhotoSelect(e,projId){
  const file=e.target.files[0]; if(!file) return;
  const reader=new FileReader();
  reader.onload=ev=>{
    const key='crochet_photo_proj_'+projId;
    localStorage.setItem(key,ev.target.result);
    const p=projects.find(x=>x.id===projId);
    if(p){p.photoKey=key;saveProjects();renderProjectDetail(p);}
  };
  reader.readAsDataURL(file);
}
function removeProjectPhoto(projId){
  const p=projects.find(x=>x.id===projId);if(!p)return;
  if(p.photoKey){localStorage.removeItem(p.photoKey);p.photoKey=null;}
  saveProjects();renderProjectDetail(p);
}

// ── Pattern library ───────────────────────────────────────────────
function renderLibrary(){
  const q=document.getElementById('lib-search').value.toLowerCase();
  const cat=document.getElementById('lib-cat-filter').value;
  const list=patterns.filter(p=>
    (!q||p.name.toLowerCase().includes(q)||(p.notes||'').toLowerCase().includes(q))&&
    (!cat||p.category===cat));
  document.getElementById('lib-count-lbl').textContent=
    `${patterns.length} pattern${patterns.length!==1?'s':''}`;
  const grid=document.getElementById('lib-grid');
  if(!list.length){grid.innerHTML='<div class="empty">No patterns yet.</div>';return;}
  grid.innerHTML=list.map(p=>{
    const imgs=getPatternImages(p.id);
    const previewImg=imgs.length?imgs[0]:null;
    const photoHeader=previewImg
      ?`<img class="card-photo-pattern" src="${previewImg}" alt="${esc(p.name)} preview"/>`
      :`<div class="card-photo-placeholder" style="height:110px">
          <svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg" width="40" height="40" opacity="0.45">
            <rect x="6" y="10" width="36" height="28" rx="4" stroke="#9b8ec4" stroke-width="2"/>
            <circle cx="17" cy="20" r="3" stroke="#9b8ec4" stroke-width="2"/>
            <path d="M6 32l9-8 7 7 5-4 9 9" stroke="#9b8ec4" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
          </svg>
        </div>`;
    return `<div class="card" onclick="goToDetail('pattern',${p.id},'library')">
      ${photoHeader}
      <button class="fav-btn${p.fav?' active':''}" onclick="event.stopPropagation();toggleFavPat(${p.id})" aria-label="Favourite">${p.fav?'★':'☆'}</button>
      <div class="card-body">
        <div class="card-title">${esc(p.name)}</div>
        <div class="card-badges">
          ${p.category?`<span class="cat-tag">${esc(p.category)}</span>`:''}
          ${p.difficulty?`<span class="crochet-level-tag">${esc(p.difficulty)}</span>`:''}
          ${p.pdfName?`<span class="pdf-badge">📄 PDF</span>`:''}
        </div>
      </div>
    </div>`;
  }).join('');
}
function toggleFavPat(id){
  const p=patterns.find(x=>x.id===id);if(p){p.fav=!p.fav;savePatterns();renderLibrary();}
}

// Add / remove images from within the edit screen — refreshes the photos section in place
function addPatternImageInEdit(patId){
  const inp=document.createElement('input');
  inp.type='file'; inp.accept='image/*'; inp.multiple=true;
  inp.onchange=e=>{
    const files=Array.from(e.target.files); if(!files.length) return;
    let loaded=0;
    const imgs=getPatternImages(patId);
    files.forEach(file=>{
      const r=new FileReader();
      r.onload=ev=>{
        imgs.push(ev.target.result);
        savePatternImages(patId,imgs);
        loaded++;
        if(loaded===files.length) refreshEditPhotos(patId);
      };
      r.readAsDataURL(file);
    });
  };
  inp.click();
}
function removePatternImageInEdit(patId,idx){
  const imgs=getPatternImages(patId);
  imgs.splice(idx,1);
  savePatternImages(patId,imgs);
  refreshEditPhotos(patId);
}
function refreshEditPhotos(patId){
  // Rebuild just the photos section inside the edit screen without losing other field values
  const p=patterns.find(x=>x.id===patId); if(!p) return;
  const imgs=getPatternImages(patId);
  const thumbs=imgs.map((src,i)=>`
    <div style="position:relative;display:inline-block">
      <img src="${src}" style="width:72px;height:72px;object-fit:cover;border-radius:var(--r);display:block"/>
      <button onclick="removePatternImageInEdit(${patId},${i})"
        style="position:absolute;top:-6px;right:-6px;background:#fff;border:1.5px solid var(--bd);
        border-radius:50%;width:20px;height:20px;font-size:11px;cursor:pointer;
        display:flex;align-items:center;justify-content:center;color:var(--tx2);padding:0">✕</button>
    </div>`).join('');
  const photoGrid=`<div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
    ${thumbs}
    <div onclick="addPatternImageInEdit(${patId})"
      style="width:72px;height:72px;border:2px dashed var(--bd2);border-radius:var(--r);
      display:flex;flex-direction:column;align-items:center;justify-content:center;
      gap:4px;cursor:pointer;background:var(--bg2);font-size:22px;color:var(--tx2)">
      📷<span style="font-size:10px;font-weight:700;color:var(--tx2)">Add</span>
    </div>
  </div>`;
  const photoSection=document.getElementById('edit-photo-section');
  if(photoSection) photoSection.innerHTML=photoGrid;
}

// ── Pattern image gallery ─────────────────────────────────────────
function getPatternImages(id){
  try{ return JSON.parse(localStorage.getItem('crochet_pat_imgs_'+id)||'[]'); }catch{ return []; }
}
function savePatternImages(id,imgs){ localStorage.setItem('crochet_pat_imgs_'+id,JSON.stringify(imgs)); }
function addPatternImage(patId){
  const inp=document.createElement('input');
  inp.type='file'; inp.accept='image/*'; inp.multiple=true;
  inp.onchange=e=>{
    const files=Array.from(e.target.files);
    let loaded=0;
    const imgs=getPatternImages(patId);
    files.forEach(file=>{
      const r=new FileReader();
      r.onload=ev=>{
        imgs.push(ev.target.result);
        savePatternImages(patId,imgs);
        loaded++;
        if(loaded===files.length){
          const p=patterns.find(x=>x.id===patId);
          if(p) renderPatternDetail(p);
        }
      };
      r.readAsDataURL(file);
    });
  };
  inp.click();
}
function removePatternImage(patId,idx){
  const imgs=getPatternImages(patId);
  imgs.splice(idx,1);
  savePatternImages(patId,imgs);
  const p=patterns.find(x=>x.id===patId);
  if(p) renderPatternDetail(p);
}
function galleryThumbClick(el){
  const pid=parseInt(el.getAttribute('data-pid'));
  const idx=parseInt(el.getAttribute('data-idx'));
  const imgs=getPatternImages(pid);
  const src=imgs[idx];
  setActiveGalleryImg(src);
}
function setActiveGalleryImg(src){
  const main=document.getElementById('gallery-main-img');
  if(main){ main.src=src; }
  document.querySelectorAll('.gallery-thumb').forEach(t=>{
    t.classList.toggle('active', t.getAttribute('data-src')===src);
  });
}

function buildPatternGallery(p){
  const imgs=getPatternImages(p.id);
  if(!imgs.length){
    return ''; // no images — hidden in read view; add photos via Edit
  }
  let thumbs='';
  for(let i=0;i<imgs.length;i++){
    const active=i===0?' active':'';
    thumbs+='<img class="gallery-thumb'+active+'" src="'+imgs[i]+'" data-idx="'+i+'" data-pid="'+p.id+'" data-src="'+imgs[i]+'" onclick="galleryThumbClick(this)" alt=""/>';
  }
  thumbs+='<div class="gallery-thumb-add" onclick="addPatternImage('+p.id+')" title="Add image">+</div>';
  return '<div class="gallery-wrap"><img id="gallery-main-img" class="gallery-main" src="'+imgs[0]+'" alt="Pattern preview"/><div class="gallery-thumbs">'+thumbs+'</div></div>';
}

// ── Pattern detail ────────────────────────────────────────────────
function renderPatternDetail(p){
  const usedIn=projects.filter(pr=>pr.patternId===p.id);
  const imgs=getPatternImages(p.id);
  let imgHtml;
  if(imgs.length){
    let thumbs='';
    for(let i=0;i<imgs.length;i++){
      const active=i===0?' active':'';
      thumbs+=`<img class="gallery-thumb${active}" src="${imgs[i]}" data-idx="${i}" data-pid="${p.id}" data-src="${imgs[i]}" onclick="galleryThumbClick(this)" alt=""/>`;
    }
    thumbs+=`<div class="gallery-thumb-add" onclick="addPatternImage(${p.id})" title="Add image">+</div>`;
    imgHtml=`<img id="gallery-main-img" class="pat-detail-main-img" src="${imgs[0]}" alt="Pattern preview"/>
             <div class="gallery-thumbs" style="padding:0 1.25rem 1rem">${thumbs}</div>`;
  } else {
    imgHtml=`<div class="pat-detail-placeholder">
      <svg viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg" width="52" height="52" opacity="0.4">
        <rect x="6" y="10" width="36" height="28" rx="4" stroke="#9b8ec4" stroke-width="2"/>
        <circle cx="17" cy="20" r="3" stroke="#9b8ec4" stroke-width="2"/>
        <path d="M6 32l9-8 7 7 5-4 9 9" stroke="#9b8ec4" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
      </svg>
    </div>`;
  }
  document.getElementById('d-content').innerHTML=`
    <div style="max-width:640px;margin:0 auto">
      <div class="pat-detail-img-wrap">
        ${imgHtml}
        <button onclick="toggleFavDetail()" id="hero-fav-btn" class="fav-btn${p.fav?' active':''}">${p.fav?'★':'☆'}</button>
      </div>
      <div class="detail-body">
        <div class="pat-detail-header">
          <div class="pat-detail-name">${esc(p.name)}</div>
          ${(p.category||p.difficulty||p.pdfName)?`<div class="card-badges">
            ${p.category?`<span class="pat-tag">${esc(p.category)}</span>`:''}
            ${p.difficulty?diffBadge(p.difficulty):''}
            ${p.pdfName?`<span class="pdf-badge">📄 PDF</span>`:''}
          </div>`:''}
        </div>
        ${(p.yarn||p.hook)?`<div class="section">
          <div class="section-lbl">Materials (pattern defaults)</div>
          <div class="chips">
            ${p.yarn?`<div class="chip"><span>🧶</span><span>${esc(p.yarn)}</span></div>`:''}
            ${p.hook?`<div class="chip"><span>🪝</span><span>Hook ${esc(p.hook)}</span></div>`:''}
          </div>
        </div>`:''}
        ${p.notes?`<div class="section">
          <div class="section-lbl">Steps &amp; notes</div>
          <div style="background:rgba(255,255,255,.7);border-radius:0 var(--rl) var(--rl) 0;padding:10px 14px 12px;
            font-size:14px;line-height:1.7;white-space:pre-wrap;border-left:3px solid var(--ac)">${esc(p.notes)}</div>
        </div>`:''}
        ${usedIn.length?`<div class="section">
          <div class="section-lbl">Used in projects</div>
          <div style="display:flex;flex-direction:column;gap:8px">
            ${usedIn.map(pr=>`
              <div class="pattern-ref-card" onclick="goToDetail('project',${pr.id},'library')">
                <div class="pattern-ref-icon">🪡</div>
                <div style="flex:1">
                  <div class="pattern-ref-name">${esc(pr.name)}</div>
                  <div class="pattern-ref-meta">${pr.status}${pr.startDate?' · '+pr.startDate:''}</div>
                </div>
                <span style="color:var(--ac);font-size:18px">›</span>
              </div>`).join('')}
          </div>
        </div>`:''}
      </div>
      <div class="detail-bar">
        ${p.pdfName?`<button class="btn-pdf-open" onclick="viewPdf(${p.id})">📄 Open PDF</button>`:''}
        <button class="btn-add" onclick="openNewProjectFromPattern(${p.id})"
          style="padding:9px 16px;font-size:13px">+ Start project</button>
        <div style="flex:1"></div>
      </div>
    </div>`;
}

// ── Steps ─────────────────────────────────────────────────────────
function getProjStepsDone(id){try{return JSON.parse(localStorage.getItem('crochet_psteps_'+id)||'[]');}catch{return[];}}
function saveProjStepsDone(id,done){localStorage.setItem('crochet_psteps_'+id,JSON.stringify(done));}
function toggleProjStep(id,idx){
  const done=getProjStepsDone(id),pos=done.indexOf(idx);
  if(pos===-1)done.push(idx);else done.splice(pos,1);
  saveProjStepsDone(id,done);refreshProjSteps(id);
}
function resetProjSteps(id){saveProjStepsDone(id,[]);refreshProjSteps(id);}
function refreshProjSteps(id){
  const p=projects.find(x=>x.id===id);if(!p)return;
  const pat=patterns.find(x=>x.id===p.patternId);
  const lines=pat?(pat.notes||'').split('\n').filter(l=>l.trim()):(p.steps||[]);
  const done=getProjStepsDone(id),total=lines.length;
  const doneCount=done.filter(i=>i<total).length;
  const pct=total?Math.round(doneCount/total*100):0;
  const bar=document.getElementById('steps-bar-'+id);
  const lbl=document.getElementById('steps-lbl-'+id);
  const pctEl=document.getElementById('steps-pct-'+id);
  if(bar)bar.style.width=pct+'%';
  if(lbl)lbl.textContent=`${doneCount} of ${total}`;
  if(pctEl)pctEl.textContent=pct+'%';
  const mascot=document.getElementById('steps-mascot-'+id);
  if(mascot)mascot.style.left=Math.min(Math.max(pct,4),96)+'%';
  // refresh section dots
  const p2=projects.find(x=>x.id===id);if(!p2)return;
  const pat2=patterns.find(x=>x.id===p2.patternId);
  const lines2=pat2?(pat2.notes||'').split('\n').filter(l=>l.trim()):(p2.steps||[]);
  document.querySelectorAll('[id^="sec-'+id+'-"]').forEach(sec=>{
    const dot=sec.querySelector('.steps-section-dot');if(!dot)return;
    const stepRows=sec.querySelectorAll('.step-row');
    const secTotal=stepRows.length,secDone=sec.querySelectorAll('.step-row.done').length;
    dot.className='steps-section-dot'+(secDone===0?'':secDone===secTotal?' full':' partial');
  });
  lines.forEach((_,i)=>{
    const row=document.getElementById(`pstep-${id}-${i}`);
    if(row)row.classList.toggle('done',done.includes(i));
  });
  const finishWrap=document.getElementById('finish-btn-wrap-'+id);
  if(finishWrap) finishWrap.style.display=(total>0&&doneCount===total)?'block':'none';
}

function finishProject(id){
  const p=projects.find(x=>x.id===id);
  if(!p||p.status==='Done') return;
  p.status='Done';
  saveProjects();
  renderProjectDetail(p);
  renderProjects();
  launchConfetti();
  setTimeout(()=>showFinishToast(id), 600);
}

// ── Edit screen navigation ────────────────────────────────────────
// editFrom: the screen to return to ('projects' | 'library' | 'detail')
let editFrom = 'projects';
let editSubmitFn = null; // set before opening edit screen

let editDeleteFn = null;

function openEditScreen(title, formHTML, submitFn, from){
  editFrom = from || activeTab;
  editSubmitFn = submitFn;
  editDeleteFn = null;
  const titleEl = document.getElementById('edit-screen-title');
  if(titleEl) titleEl.textContent = title;
  document.getElementById('edit-content').innerHTML = formHTML;
  // Always hide delete btn by default; callers can show it
  document.getElementById('edit-delete-btn').style.display='none';
  // Hide the from-screen, show edit
  const fromEl = editFrom === 'detail' ? document.getElementById('s-detail') : document.getElementById('s-'+editFrom);
  fromEl.classList.replace('on','off-left');
  document.getElementById('s-edit').classList.replace('off-right','on');
  document.getElementById('s-edit').scrollTop = 0;
  document.getElementById('main-tab-bar').style.display='none';
}

function triggerEditDelete(){
  if(editDeleteFn) editDeleteFn();
}

function closeEditScreen(){
  document.getElementById('s-edit').classList.replace('on','off-right');
  const fromEl = editFrom === 'detail' ? document.getElementById('s-detail') : document.getElementById('s-'+editFrom);
  fromEl.classList.replace('off-left','on');
  if(editFrom !== 'detail') document.getElementById('main-tab-bar').style.display='';
  pendingPdfData=null; pendingPdfName=null;
}

function submitEditScreen(){
  if(editSubmitFn) editSubmitFn();
}

function openNewProject(prePatternId){
  openEditScreen('New project', projectFormHTML(null, prePatternId), saveNewProject, activeTab);
}
function openEditProject(id){
  const p=projects.find(x=>x.id===id);
  if(!p) return;
  openEditScreen('Edit project', projectFormHTML(p), ()=>saveEditProject(id), 'detail');
  editDeleteFn = ()=>deleteProject(id);
  document.getElementById('edit-delete-btn').style.display='';
}
function openNewProjectFromPattern(patternId){
  goBack();
  openNewProject(patternId);
}
function openNewPattern(){
  openEditScreen('Add to library', patternFormHTML(null), saveNewPattern, activeTab);
}
function openEditPattern(id){
  const p=patterns.find(x=>x.id===id);
  if(!p) return;
  openEditScreen('Edit pattern', patternFormHTML(p), ()=>saveEditPattern(id), 'detail');
  editDeleteFn = ()=>deletePattern(id);
  document.getElementById('edit-delete-btn').style.display='';
}
// Keep closeModal as no-op for any lingering references
function closeModal(){}

function projectFormHTML(p,prePatternId){
  const statuses=['Active','Done','Frogged'];
  const selPatId=p?p.patternId:(prePatternId||null);
  const pickerItems=`
    <div class="picker-none${selPatId===null?' selected':''}" id="pick-none" onclick="selectPattern(null)">
      <div class="picker-item-icon" style="background:linear-gradient(135deg,#c9b8ff,#e0d4ff)">✦</div>
      <div>
        <div class="picker-item-name">Freestyle</div>
        <div class="picker-item-meta">No pattern — freeform project</div>
      </div>
    </div>
    ${patterns.map(pat=>{
      const imgs=getPatternImages(pat.id);
      const thumb=imgs.length
        ?`<img src="${imgs[0]}" style="width:36px;height:36px;border-radius:var(--r);object-fit:cover;flex-shrink:0" alt=""/>`
        :`<div class="picker-item-icon">📄</div>`;
      return `<div class="picker-item${selPatId===pat.id?' selected':''}" id="pick-${pat.id}" onclick="selectPattern(${pat.id})">
        ${thumb}
        <div>
          <div class="picker-item-name">${esc(pat.name)}</div>
          <div class="picker-item-meta">${[pat.category,pat.difficulty].filter(Boolean).join(' · ')}</div>
        </div>
      </div>`;
    }).join('')}`;

  return `
    <div class="form-row"><label>Project name</label>
      <input id="pj-name" value="${p?esc(p.name):''}" placeholder="e.g. Blanket for Mum"/></div>
    <div class="form-row"><label>Status</label>
      <select id="pj-status">${statuses.map(s=>`<option${p&&p.status===s?' selected':''}>${s}</option>`).join('')}</select></div>
    <div class="form-row"><label>Pattern (optional)</label>
      <div class="picker-list">${pickerItems}</div>
      <input type="hidden" id="pj-pat-id" value="${selPatId!==null?selPatId:''}"/>
    </div>
    ${!p||!p.patternId?`<div class="form-row"><label>Your steps (one per line, freestyle only)</label>
      <textarea id="pj-steps" placeholder="Each line becomes a tappable step…">${p&&p.steps?(p.steps||[]).join('\n'):''}</textarea></div>`:''}
    <div class="form-row-2">
      <div class="form-row" style="margin-bottom:0"><label>Yarn</label>
        <input id="pj-yarn" value="${p?esc(p.yarn||''):''}" placeholder="e.g. Drops Lima – Teal"/></div>
      <div class="form-row" style="margin-bottom:0"><label>Hook</label>
        <input id="pj-hook" value="${p?esc(p.hook||''):''}" placeholder="e.g. 5.0mm"/></div>
    </div>
    <div class="form-row-2">
      <div class="form-row" style="margin-bottom:0"><label>Start date</label>
        <input type="date" id="pj-start" value="${p?p.startDate||'':''}"/></div>
      <div class="form-row" style="margin-bottom:0"><label>End date</label>
        <input type="date" id="pj-end" value="${p?p.endDate||'':''}"/></div>
    </div>
    <div class="form-row"><label>Notes</label>
      <textarea id="pj-notes" placeholder="Notes specific to this make…">${p?esc(p.notes||''):''}</textarea></div>
    <div class="edit-save-footer">
      <button class="btn-save-bottom" onclick="submitEditScreen()">${p?'Save project':'Create project'}</button>
    </div>
  `;
}

function selectPattern(id){
  document.getElementById('pj-pat-id').value = id===null?'':id;
  document.querySelectorAll('.picker-item,.picker-none').forEach(el=>el.classList.remove('selected'));
  const target=id===null?document.getElementById('pick-none'):document.getElementById('pick-'+id);
  if(target) target.classList.add('selected');
  // Show/hide freestyle steps textarea (only present when creating a new project)
  const stepsEl=document.getElementById('pj-steps');
  if(stepsEl){
    const stepsRow=stepsEl.closest('.form-row');
    if(stepsRow) stepsRow.style.display=id===null?'':'none';
  }
}

function saveNewProject(){
  const name=document.getElementById('pj-name').value.trim();
  if(!name){document.getElementById('pj-name').style.borderColor='#e24b4a';return;}
  const patId=document.getElementById('pj-pat-id').value;
  const stepsEl=document.getElementById('pj-steps');
  const steps=stepsEl?stepsEl.value.split('\n').filter(l=>l.trim()):[];
  const id=nextProjId++;
  // Inherit first image from selected pattern
  let photoKey=null;
  if(patId){
    const patImgs=getPatternImages(parseInt(patId));
    if(patImgs.length){
      photoKey='crochet_photo_proj_'+id;
      localStorage.setItem(photoKey,patImgs[0]);
    }
  }
  projects.push({id,name,
    patternId:patId?parseInt(patId):null,
    steps:patId?[]:steps,
    status:document.getElementById('pj-status').value,
    yarn:document.getElementById('pj-yarn').value.trim(),
    hook:document.getElementById('pj-hook').value.trim(),
    startDate:document.getElementById('pj-start').value||null,
    endDate:document.getElementById('pj-end').value||null,
    notes:document.getElementById('pj-notes').value.trim(),
    fav:false,photoKey});
  saveProjects();closeEditScreen();renderProjects();
}
function saveEditProject(id){
  const p=projects.find(x=>x.id===id);
  const name=document.getElementById('pj-name').value.trim();
  if(!name){document.getElementById('pj-name').style.borderColor='#e24b4a';return;}
  const patId=document.getElementById('pj-pat-id').value;
  const stepsEl=document.getElementById('pj-steps');
  const oldStatus = p.status;
  p.name=name; p.status=document.getElementById('pj-status').value;
  p.patternId=patId?parseInt(patId):null;
  p.steps=patId?[]:(stepsEl?stepsEl.value.split('\n').filter(l=>l.trim()):[]);
  p.yarn=document.getElementById('pj-yarn').value.trim();
  p.hook=document.getElementById('pj-hook').value.trim();
  p.startDate=document.getElementById('pj-start').value||null;
  p.endDate=document.getElementById('pj-end').value||null;
  p.notes=document.getElementById('pj-notes').value.trim();
  const justFinished = p.status === 'Done' && oldStatus !== 'Done';
  saveProjects();
  if(currentDetailId===id&&currentDetailType==='project') renderProjectDetail(p);
  renderProjects();
  closeEditScreen();
  if(justFinished){ launchConfetti(); setTimeout(()=>showFinishToast(id), 600); }
}
function deleteProject(id){
  if(!confirm('Delete this project?'))return;
  localStorage.removeItem('crochet_psteps_'+id);
  const p=projects.find(x=>x.id===id);
  if(p?.photoKey) localStorage.removeItem(p.photoKey);
  projects=projects.filter(x=>x.id!==id);
  saveProjects();
  // Close edit screen first, then detail, then land on list
  document.getElementById('s-edit').classList.replace('on','off-right');
  document.getElementById('s-detail').classList.replace('off-left','on');
  setTimeout(()=>{
    goBack(); // detail → list
    renderProjects();
  }, 0);
}

// ── Pattern form ──────────────────────────────────────────────────
function patternFormHTML(p){
  const cats=['Amigurumi','Blanket','Hat','Shawl','Bag','Clothing','Home decor','Other'];
  const diffs=['Easy','Medium','Hard'];
  return `
    <div class="form-row"><label>Pattern name</label>
      <input id="f-name" value="${p?esc(p.name):''}" placeholder="e.g. Bunny amigurumi"/></div>
    <div class="form-row-2">
      <div class="form-row" style="margin-bottom:0"><label>Category</label>
        <select id="f-cat">${cats.map(c=>`<option${p&&p.category===c?' selected':''}>${c}</option>`).join('')}</select></div>
      <div class="form-row" style="margin-bottom:0"><label>Difficulty</label>
        <select id="f-diff">${diffs.map(d=>`<option${p&&p.difficulty===d?' selected':''}>${d}</option>`).join('')}</select></div>
    </div>
    <div class="form-row-2">
      <div class="form-row" style="margin-bottom:0"><label>Default yarn</label>
        <input id="f-yarn" value="${p?esc(p.yarn||''):''}" placeholder="e.g. Drops Safran"/></div>
      <div class="form-row" style="margin-bottom:0"><label>Default hook</label>
        <input id="f-hook" value="${p?esc(p.hook||''):''}" placeholder="e.g. 4.0mm"/></div>
    </div>
    <div class="form-row"><label>Steps / notes (one per line)</label>
      <textarea id="f-notes" placeholder="Each line becomes a tappable step in projects…" style="min-height:140px">${p?esc(p.notes||''):''}</textarea></div>
    ${p?`<div class="form-row"><label>Photos</label>
      ${(()=>{
        const imgs=getPatternImages(p.id);
        const thumbs=imgs.map((src,i)=>`
          <div style="position:relative;display:inline-block">
            <img src="${src}" style="width:72px;height:72px;object-fit:cover;border-radius:var(--r);display:block"/>
            <button onclick="removePatternImageInEdit(${p.id},${i})"
              style="position:absolute;top:-6px;right:-6px;background:#fff;border:1.5px solid var(--bd);
              border-radius:50%;width:20px;height:20px;font-size:11px;cursor:pointer;
              display:flex;align-items:center;justify-content:center;color:var(--tx2);padding:0">✕</button>
          </div>`).join('');
        return `<div id="edit-photo-section" style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
          ${thumbs}
          <div onclick="addPatternImageInEdit(${p.id})"
            style="width:72px;height:72px;border:2px dashed var(--bd2);border-radius:var(--r);
            display:flex;flex-direction:column;align-items:center;justify-content:center;
            gap:4px;cursor:pointer;background:var(--bg2);transition:background .15s;font-size:22px;color:var(--tx2)">
            📷
            <span style="font-size:10px;font-weight:700;color:var(--tx2)">Add</span>
          </div>
        </div>`;
      })()}
    </div>`:''}
    <div class="edit-save-footer">
      <button class="btn-save-bottom" onclick="submitEditScreen()">${p?'Save pattern':'Add pattern'}</button>
    </div>
  `;
}
function saveNewPattern(){
  const name=document.getElementById('f-name').value.trim();
  if(!name){document.getElementById('f-name').style.borderColor='#e24b4a';return;}
  const id=nextPatId++;
  patterns.push({id,name,
    category:document.getElementById('f-cat').value,
    difficulty:document.getElementById('f-diff').value,
    yarn:document.getElementById('f-yarn').value.trim(),
    hook:document.getElementById('f-hook').value.trim(),
    notes:document.getElementById('f-notes').value.trim(),
    fav:false,pdfName:pendingPdfName||null});
  if(pendingPdfData)localStorage.setItem('crochet_pdf_'+id,pendingPdfData);
  pendingPdfData=null;pendingPdfName=null;
  savePatterns();closeEditScreen();renderLibrary();
}
function saveEditPattern(id){
  const p=patterns.find(x=>x.id===id);
  const name=document.getElementById('f-name').value.trim();
  if(!name){document.getElementById('f-name').style.borderColor='#e24b4a';return;}
  p.name=name;p.category=document.getElementById('f-cat').value;
  p.difficulty=document.getElementById('f-diff').value;
  p.yarn=document.getElementById('f-yarn').value.trim();
  p.hook=document.getElementById('f-hook').value.trim();
  p.notes=document.getElementById('f-notes').value.trim();
  if(pendingPdfData){localStorage.setItem('crochet_pdf_'+id,pendingPdfData);p.pdfName=pendingPdfName;pendingPdfData=null;pendingPdfName=null;}
  savePatterns();
  if(currentDetailId===id&&currentDetailType==='pattern') renderPatternDetail(p);
  renderLibrary();
  closeEditScreen();
}
function deletePattern(id){
  if(!confirm('Delete this pattern? Projects using it will lose their pattern link.'))return;
  localStorage.removeItem('crochet_pdf_'+id);
  localStorage.removeItem('crochet_pat_imgs_'+id);
  patterns=patterns.filter(x=>x.id!==id);
  savePatterns();
  // Close edit screen, then detail, then land on library
  document.getElementById('s-edit').classList.replace('on','off-right');
  document.getElementById('s-detail').classList.replace('off-left','on');
  setTimeout(()=>{
    goBack(); // detail → library
    renderLibrary();
  }, 0);
}

// ── PDF ───────────────────────────────────────────────────────────
let pendingPdfData=null,pendingPdfName=null;
function handlePdfSelect(e){const f=e.target.files[0];if(f)loadPdf(f);}
function handlePdfDrop(e){
  e.preventDefault();document.getElementById('pdf-dz').classList.remove('drag-over');
  const f=e.dataTransfer.files[0];if(f&&f.type==='application/pdf')loadPdf(f);
}
function loadPdf(file){
  const r=new FileReader();
  r.onload=ev=>{
    pendingPdfData=ev.target.result;pendingPdfName=file.name;
    const dz=document.getElementById('pdf-dz'),pr=document.getElementById('pdf-preview'),nm=document.getElementById('pdf-preview-name');
    if(dz)dz.style.display='none';if(pr)pr.style.display='flex';if(nm)nm.textContent='📄 '+file.name;
  };
  r.readAsDataURL(file);
}
function clearPdfPreview(){
  pendingPdfData=null;pendingPdfName=null;
  const dz=document.getElementById('pdf-dz'),pr=document.getElementById('pdf-preview');
  if(dz)dz.style.display='';if(pr)pr.style.display='none';
}
function removePdf(id){
  const p=patterns.find(x=>x.id===id);if(!p)return;
  if(!confirm('Remove PDF?'))return;
  localStorage.removeItem('crochet_pdf_'+id);p.pdfName=null;savePatterns();
  // Reopen edit screen to reflect removed PDF (preserves other field values via re-render)
  openEditPattern(id);
}
function viewPdf(id){
  const data=localStorage.getItem('crochet_pdf_'+id);
  const p=patterns.find(x=>x.id===id);
  if(!data){alert('PDF not found.');return;}
  const v=document.createElement('div');v.className='pdf-viewer';v.id='pdf-viewer';
  v.innerHTML=`<div class="pdf-bar"><span>📄 ${p?esc(p.pdfName||p.name):'PDF'}</span>
    <button onclick="document.getElementById('pdf-viewer').remove()">✕</button></div>
    <iframe class="pdf-iframe" src="${data}"></iframe>`;
  document.body.appendChild(v);
}


// ── Swipe-back gesture ────────────────────────────────────────────
(function(){
  const EDGE_THRESHOLD = 22;   // px from left edge to start gesture
  const COMPLETE_RATIO = 0.38; // fraction of screen width to trigger back
  const VELOCITY_THRESHOLD = 0.4; // px/ms to trigger even on short swipe

  let tracking = false;
  let startX = 0, startY = 0, lastX = 0, lastTime = 0;
  let activeFg = null, activeBg = null;
  let backFn = null;
  let axisLocked = null; // 'h' | 'v' | null

  function getActiveContext(){
    const editOn  = document.getElementById('s-edit').classList.contains('on');
    const detailOn = document.getElementById('s-detail').classList.contains('on');
    if(editOn){
      const bg = editFrom === 'detail'
        ? document.getElementById('s-detail')
        : document.getElementById('s-'+editFrom);
      return { fg: document.getElementById('s-edit'), bg, fn: closeEditScreen };
    }
    if(detailOn){
      const bg = document.getElementById('s-'+detailFrom);
      return { fg: document.getElementById('s-detail'), bg, fn: goBack };
    }
    return null;
  }

  function setTransition(el, on){
    el.style.transition = on
      ? 'transform .3s cubic-bezier(.4,0,.2,1)'
      : 'none';
  }

  function onStart(e){
    const t = e.touches[0];
    if(t.clientX > EDGE_THRESHOLD) return;
    const ctx = getActiveContext();
    if(!ctx) return;
    tracking = true;
    axisLocked = null;
    startX = lastX = t.clientX;
    startY = t.clientY;
    lastTime = Date.now();
    activeFg = ctx.fg;
    activeBg = ctx.bg;
    backFn   = ctx.fn;
    // Prepare bg: slide it in from the left, slightly behind
    setTransition(activeFg, false);
    setTransition(activeBg, false);
    activeBg.classList.replace('off-left','on');
    activeBg.style.transform = 'translateX(-28%)';
  }

  function onMove(e){
    if(!tracking) return;
    const t = e.touches[0];
    const dx = t.clientX - startX;
    const dy = t.clientY - startY;

    // Lock axis on first significant movement
    if(!axisLocked){
      if(Math.abs(dx) > 6 || Math.abs(dy) > 6){
        axisLocked = Math.abs(dx) >= Math.abs(dy) ? 'h' : 'v';
      }
    }
    if(axisLocked === 'v'){ cancel(); return; }
    if(axisLocked !== 'h') return;

    e.preventDefault();
    lastTime = Date.now();
    const clampedDx = Math.max(0, dx);
    const ratio = clampedDx / window.innerWidth;
    // fg slides right with finger
    activeFg.style.transform = `translateX(${clampedDx}px)`;
    // bg parallax: starts at -28%, moves toward 0
    const bgX = -28 + ratio * 28;
    activeBg.style.transform = `translateX(${bgX}%)`;
    lastX = t.clientX;
  }

  function onEnd(e){
    if(!tracking) return;
    tracking = false;
    if(!axisLocked || axisLocked === 'v'){ cancel(); return; }

    const dx = lastX - startX;
    const elapsed = Date.now() - lastTime + 1;
    const velocity = dx / elapsed;
    const ratio = dx / window.innerWidth;

    if(dx > 0 && (ratio >= COMPLETE_RATIO || velocity >= VELOCITY_THRESHOLD)){
      complete();
    } else {
      cancel();
    }
  }

  function complete(){
    // Animate fg off-right and bg to full position, then call back function
    setTransition(activeFg, true);
    setTransition(activeBg, true);
    activeFg.style.transform = `translateX(100%)`;
    activeBg.style.transform = `translateX(0)`;
    activeFg.addEventListener('transitionend', function handler(){
      activeFg.removeEventListener('transitionend', handler);
      // Reset inline styles — backFn will set the classes
      activeFg.style.transform = '';
      activeBg.style.transform = '';
      setTransition(activeFg, true);
      setTransition(activeBg, true);
      backFn();
    }, {once:true});
  }

  function cancel(){
    if(!activeFg) return;
    setTransition(activeFg, true);
    setTransition(activeBg, true);
    activeFg.style.transform = '';
    activeBg.style.transform = 'translateX(-28%)';
    activeFg.addEventListener('transitionend', function handler(){
      activeFg.removeEventListener('transitionend', handler);
      activeBg.style.transform = '';
      activeBg.classList.replace('on','off-left');
      setTransition(activeFg, true);
      setTransition(activeBg, true);
    }, {once:true});
    activeFg = activeBg = backFn = null;
    axisLocked = null;
  }

  document.addEventListener('touchstart',  onStart, {passive:true});
  document.addEventListener('touchmove',   onMove,  {passive:false});
  document.addEventListener('touchend',    onEnd,   {passive:true});
  document.addEventListener('touchcancel', ()=>{ tracking=false; cancel(); }, {passive:true});
})();

// ── Tab swipe gesture (Projects ↔ Library) ────────────────────────
(function(){
  const MIN_SWIPE  = 50;       // px minimum horizontal distance
  const VELOCITY   = 0.3;      // px/ms fast-flick threshold
  const EDGE_GUARD = 40;       // px dead zone on each edge (avoids Android system gestures)

  let tracking = false, startX = 0, startY = 0, lastX = 0, startTime = 0;
  let axisLocked = null;

  function isTabView(){
    return !document.getElementById('s-edit').classList.contains('on') &&
           !document.getElementById('s-detail').classList.contains('on');
  }

  function onStart(e){
    if(!isTabView()) return;
    const t = e.touches[0];
    // Ignore touches that start in the Android system gesture zones (left/right edges)
    if(t.clientX < EDGE_GUARD || t.clientX > window.innerWidth - EDGE_GUARD) return;
    tracking   = true;
    axisLocked = null;
    startX = lastX = t.clientX;
    startY     = t.clientY;
    startTime  = Date.now();
  }

  function onMove(e){
    if(!tracking) return;
    const t  = e.touches[0];
    const dx = t.clientX - startX;
    const dy = t.clientY - startY;
    if(!axisLocked){
      if(Math.abs(dx) > 8 || Math.abs(dy) > 8)
        axisLocked = Math.abs(dx) >= Math.abs(dy) ? 'h' : 'v';
    }
    if(axisLocked === 'h') e.preventDefault();
    lastX = t.clientX;
  }

  function onEnd(){
    if(!tracking){ tracking = false; return; }
    tracking = false;
    if(axisLocked !== 'h') return;
    const dx       = lastX - startX;
    const velocity = Math.abs(dx) / (Date.now() - startTime + 1);
    if(Math.abs(dx) >= MIN_SWIPE || velocity >= VELOCITY){
      if(dx < 0 && activeTab === 'projects') switchTab('library');
      else if(dx > 0 && activeTab === 'library') switchTab('projects');
    }
  }

  document.addEventListener('touchstart',  onStart, {passive:true});
  document.addEventListener('touchmove',   onMove,  {passive:false});
  document.addEventListener('touchend',    onEnd,   {passive:true});
  document.addEventListener('touchcancel', ()=>{ tracking = false; }, {passive:true});
})();

// ── Init ──────────────────────────────────────────────────────────
renderProjects();
if('serviceWorker'in navigator)window.addEventListener('load',()=>navigator.serviceWorker.register('sw.js').catch(()=>{}));
